// =====================================================================
// EDIT HERE: reconciliation rules (the only block most people change)
// =====================================================================
// Every row must have these columns present and non-empty. Change them to
// match your export. The dedup key below must be one of these columns.
const REQUIRED_COLUMNS = ['order_id', 'branch', 'sku', 'qty', 'amount', 'order_date'];

// Rows are deduplicated on this column. The first row wins; later rows with
// the same value are sent to the reject file as duplicates.
const KEY_COLUMN = 'order_id';

// Light format checks: 'integer', 'number', or 'date' (YYYY-MM-DD). A column
// not listed here is only checked for being present and non-empty.
const COLUMN_TYPES = { qty: 'integer', amount: 'number', order_date: 'date' };

// Output files are named <prefix>-master-YYYY-MM-DD.csv and
// <prefix>-rejects-YYYY-MM-DD.csv. The List node skips this prefix, so the
// outputs are never read back in on the next run.
const OUTPUT_PREFIX = 'reconciled';
// =====================================================================
// No need to edit below this line.
// =====================================================================

function pairedIndex(it) {
  const p = it && it.pairedItem;
  if (p == null) return null;
  if (typeof p === 'number') return p;
  if (Array.isArray(p)) return (p[0] && typeof p[0].item === 'number') ? p[0].item : null;
  return (typeof p.item === 'number') ? p.item : null;
}
function fileNameFor(it, downloadItems) {
  try {
    const idx = pairedIndex(it);
    if (idx == null) return 'unknown';
    const d = downloadItems[idx];
    const n = d && d.json && (d.json.name || d.json.fileName);
    return n ? String(n) : 'unknown';
  } catch (e) {
    return 'unknown';
  }
}
function isEmpty(v) {
  return v === undefined || v === null || String(v).trim() === '';
}
function checkType(val, type) {
  const s = String(val).trim();
  if (type === 'integer') return /^-?\d+$/.test(s);
  if (type === 'number') return s !== '' && !isNaN(Number(s)) && isFinite(Number(s));
  if (type === 'date') {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) return false;
    const d = new Date(s + 'T00:00:00Z');
    return !isNaN(d.getTime());
  }
  return true;
}
// Required columns first (in config order), then any other original columns,
// then the audit columns last so the reason sits at the end of each reject row.
function orderedRow(row, extra) {
  const out = {};
  for (const c of REQUIRED_COLUMNS) out[c] = (row[c] !== undefined ? row[c] : '');
  for (const k of Object.keys(row)) if (!(k in out)) out[k] = row[k];
  if (extra) for (const k of Object.keys(extra)) out[k] = extra[k];
  return out;
}

const parsedItems = $input.all();
const downloadItems = $('Download Each CSV').all();
const fileCount = $('List CSV Files in Folder').all().length;

const now = new Date();
const runDate = now.getUTCFullYear() + '-' +
  String(now.getUTCMonth() + 1).padStart(2, '0') + '-' +
  String(now.getUTCDate()).padStart(2, '0');

const master = [];
const rejects = [];
const seen = new Map(); // key value -> source file of the first kept row
let rowsIn = 0;
let quarantined = 0;
let duplicatesDropped = 0;
let unreadableFiles = 0;

for (const it of parsedItems) {
  const json = (it && it.json) ? it.json : {};
  const keys = Object.keys(json);

  // An Extract from File error item (routed back to the main lane) looks like
  // { error: '<message>' } and nothing else: a file that could not be parsed.
  const isErrorItem = (typeof json.error === 'string') && keys.length === 1;
  if (isErrorItem) {
    unreadableFiles++;
    rejects.push(orderedRow({}, {
      source_file: fileNameFor(it, downloadItems),
      reject_type: 'unreadable_file',
      reject_reason: 'File could not be parsed as CSV: ' + json.error,
    }));
    continue;
  }

  rowsIn++;
  const srcFile = fileNameFor(it, downloadItems);

  // ---- validation ----
  const reasons = [];
  for (const col of REQUIRED_COLUMNS) {
    if (isEmpty(json[col])) reasons.push('missing or empty required column "' + col + '"');
  }
  if (isEmpty(json[KEY_COLUMN]) && !reasons.some(r => r.indexOf('"' + KEY_COLUMN + '"') !== -1)) {
    reasons.push('empty key column "' + KEY_COLUMN + '"');
  }
  for (const col of Object.keys(COLUMN_TYPES)) {
    if (!isEmpty(json[col]) && !checkType(json[col], COLUMN_TYPES[col])) {
      reasons.push('column "' + col + '" is not a valid ' + COLUMN_TYPES[col] + ' (got "' + String(json[col]) + '")');
    }
  }

  if (reasons.length) {
    quarantined++;
    rejects.push(orderedRow(json, {
      source_file: srcFile,
      reject_type: 'invalid',
      reject_reason: reasons.join('; '),
    }));
    continue;
  }

  // ---- dedup on the key column, keeping the first occurrence ----
  const keyVal = String(json[KEY_COLUMN]).trim();
  if (seen.has(keyVal)) {
    duplicatesDropped++;
    rejects.push(orderedRow(json, {
      source_file: srcFile,
      reject_type: 'duplicate',
      reject_reason: 'duplicate ' + KEY_COLUMN + ' "' + keyVal + '" (earlier row kept from ' + seen.get(keyVal) + ')',
    }));
    continue;
  }
  seen.set(keyVal, srcFile);
  master.push(orderedRow(json, null));
}

const merged = master.length;
const masterFileName = OUTPUT_PREFIX + '-master-' + runDate + '.csv';
const rejectFileName = OUTPUT_PREFIX + '-rejects-' + runDate + '.csv';

const lines = [];
lines.push('CSV Folder Reconciler run (' + runDate + ')');
lines.push('Files read: ' + fileCount);
lines.push('Rows in: ' + rowsIn);
lines.push('Merged to master: ' + merged);
lines.push('Quarantined (invalid): ' + quarantined);
lines.push('Duplicates dropped: ' + duplicatesDropped);
if (unreadableFiles > 0) lines.push('Unreadable files: ' + unreadableFiles);
lines.push(merged > 0
  ? 'Master file: ' + masterFileName
  : 'Master file: none written (no valid rows)');
lines.push(rejects.length > 0
  ? 'Reject file: ' + rejectFileName + ' (' + rejects.length + ' rows)'
  : 'Reject file: none written (nothing quarantined)');
const recapText = lines.join('\n');

const recap = {
  runDate,
  filesRead: fileCount,
  rowsIn,
  merged,
  quarantined,
  duplicatesDropped,
  unreadableFiles,
  rejectRows: rejects.length,
  recapText,
};

return [{ json: { recap, master, rejects, masterFileName, rejectFileName, hasMaster: merged > 0, hasRejects: rejects.length > 0 } }];

// Expand the deduplicated master rows into one item per row for the CSV builder.
// No items means no valid rows, so the master CSV and its upload are skipped.
return ($input.first().json.master || []).map((json) => ({ json }));

// Expand the quarantined rows (invalid, duplicate, and unreadable files) into
// one item per row for the reject CSV builder. No items means nothing was
// quarantined, so the reject CSV and its upload are skipped this run.
return ($input.first().json.rejects || []).map((json) => ({ json }));
